function getRememberMeCookie() {
  const cookieValue = document.cookie.split('; ').find(cookie => cookie.startsWith('rememberMe='));
  if (!cookieValue) return null;
  const [username, passwordHash] = cookieValue.split(':');
  return { username, passwordHash };
}

